// 1. Leemos los datos que entran directamente por el cable a este nodo
const inputData = $input.first().json;

// 2. n8n a veces mete los datos de Slack dentro de "event", o los deja sueltos. Esto cubre ambas.
const slackEvent = inputData.event ? inputData.event : inputData;

// 3. Capturamos el texto real (con un texto de prueba por si ejecutas el nodo a mano)
const raw_text = slackEvent.text || 'dame el status https://app.example.com/records/<UUID>';

// 4. Extraemos el link de Platform
const dealMatch = raw_text.match(/app.example.com\/records\/([0-9a-fA-F-]{36})/i);
const deal_id = dealMatch ? dealMatch[1] : null;

// 5. Mandamos los datos reales al resto del flujo
return [{
  json: {
    raw_text: raw_text,
    channel_id: slackEvent.channel || '<YOUR_SLACK_CHANNEL_ID>', // Salvavidas de canal si pruebas a mano
    thread_ts: slackEvent.thread_ts || slackEvent.ts || '1620000000.000100', // Salvavidas de hilo
    slack_user_id: slackEvent.user || '<YOUR_SLACK_USER_ID>',
    deal_id: deal_id,
    application_id: deal_id,
    has_deal_link: !!deal_id
  }
}];

const appWrap = $('GET Application').first().json;
const emailWrap = $('GET Email History').first().json;
const app = appWrap.data ?? appWrap;
const business = app.business || {};
const fa = app.funding_advisor || {};
const stips = Array.isArray(app.stips) ? app.stips : [];
const missing_stips = stips
  .filter((s) => s && s.is_finished === false)
  .map((s) => s.name || s.title || s.label || s.type || 'Unnamed stip');
const logs = emailWrap.data ?? emailWrap ?? [];
const sent = (Array.isArray(logs) ? logs : [])
  .filter((e) => (e.data?.status || e.status) === 'sent')
  .sort((a, b) => new Date(b.data?.created_at || b.created_at || 0) - new Date(a.data?.created_at || a.created_at || 0));
const last = sent[0];
let last_email = null;
let minutes_since_last_email = null;
if (last) {
  const d = last.data || last;
  const at = d.created_at || d.sent_at || last.created_at;
  last_email = { subject: d.subject || '(no subject)', date: at, sender: d.sender?.name || d.sender?.email || d.from || 'Unknown' };
  if (at) minutes_since_last_email = Math.floor((Date.now() - new Date(at).getTime()) / 60000);
}
let next_action = 'All docs received — ready for submission';
if (missing_stips.length) {
  if (minutes_since_last_email == null) {
    next_action = 'Send missing docs email';
  } else if (minutes_since_last_email >= 2880) {
    next_action = 'Send missing docs email';
  } else {
    const waitH = Math.ceil((2880 - minutes_since_last_email) / 60);
    next_action = `Wait ${waitH} more hours before next missing-docs email (48h rule)`;
  }
}
const prequal = app.prequalification || {};
return [{
  json: {
    business_name: business.business_legal_name || business.name || app.application_name || 'Unknown',
    fa_name: [fa.first_name, fa.last_name].filter(Boolean).join(' ') || fa.name || 'Unassigned',
    fa_email: fa.email || '',
    stage: app.stage_name || app.stage_category || app.status?.name || 'Unknown',
    requested_amount: prequal.requested_amount ?? app.requested_amount ?? null,
    missing_stips,
    last_email,
    minutes_since_last_email,
    next_action,
    deal_id: $('Validate & Enrich Context').first().json.deal_id,
    deal_url: 'https://app.example.com/records/' + $('Validate & Enrich Context').first().json.deal_id
  }
}];

const p = $('Validate & Enrich Context').first().json;
const items = $('Execute Missing Docs').all().map((i) => i.json);
const r = items[items.length - 1] || $input.first().json || {};
let outcome = 'completed';
let summary = '';
if (r._slack_response) {
  summary = r._slack_response;
} else if (r._skip) {
  outcome = 'skipped';
  summary = 'No hay documentos pendientes para ' + (r._business_name || p.deal_id) + '.';
} else if (r._interval_ok === false) {
  outcome = 'interval_blocked';
  const mins = r._minutes_since_last ?? 0;
  const waitH = Math.max(1, Math.ceil((2880 - mins) / 60));
  summary = 'Intervalo de 48h no cumplido. Quedan aproximadamente ' + waitH + ' horas antes del próximo envío.';
} else if (r.data || r.success) {
  outcome = 'sent';
  summary = 'Email de documentos faltantes enviado correctamente.';
} else {
  outcome = 'unclear';
  summary = 'Subworkflow completado — revisa logs de ejecución.';
}
return [{ json: { outcome, summary, deal_id: p.deal_id, deal_url: 'https://app.example.com/records/' + p.deal_id } }];

const p = $('Validate & Enrich Context').first().json;
const r = $('Execute Snapshot').first().json || {};
const ok = r.success === true || r.outcome === 'platform_send_ok' || !!r.data;
return [{
  json: {
    outcome: ok ? 'sent' : 'unclear',
    summary: ok ? 'Secure Document Snapshot PDF enviado correctamente.' : 'Snapshot subworkflow terminó sin confirmación clara de envío.',
    deal_id: p.deal_id,
    deal_url: 'https://app.example.com/records/' + p.deal_id
  }
}];

const p = $('Validate & Enrich Context').first().json;
let score = null;
for (const j of $('Execute Score').all().map((i) => i.json)) {
  if (j.score_final != null) score = j;
  if (j.deal_quality_score != null) score = { score_final: j.deal_quality_score, rating: j.rating, justificacion: j.justificacion };
}
if (!score) score = $('Execute Score').first().json || {};
return [{
  json: {
    score: score.score_final ?? score.deal_quality_score ?? null,
    rating: score.rating ?? '',
    justificacion: score.justificacion ?? score.justification ?? '',
    deal_id: p.deal_id,
    deal_url: 'https://app.example.com/records/' + p.deal_id
  }
}];

// 1. Capturar los datos del contexto inicial y la IA
const context = $('Extract Context').first().json;
const aiResponse = $input.first().json;

// 2. Extraer la decisión de la IA de forma segura
let intent = aiResponse?.output?.intent || 'unknown';
let confidence = aiResponse?.output?.confidence || 0;

// 3. CASO 1: ¿La intención NO requiere datos de Platform? (help, unknown)
const requires_deal = ['status', 'missing', 'snapshot', 'score'].includes(intent);

let check_history_needed = false;
let final_intent = intent;

if (requires_deal) {
  // CASO 2: Requiere deal y SÍ tiene link en el mensaje actual
  if (context.has_deal_link) {
    check_history_needed = false;
    final_intent = intent; // Todo en orden
  } 
  // CASO 3: Requiere deal pero NO tiene link en este mensaje (Podría estar en el historial)
  else if (context.thread_ts && context.thread_ts !== "") {
    check_history_needed = true; 
    final_intent = intent; // Dejamos la intención, pero levantamos una bandera (flag)
  } 
  // Si pide deal, no hay link actual y tampoco está en un hilo (mensaje suelto)
  else {
    final_intent = 'missing_link';
  }
}

// 4. Devolver la data unificada
return [{
  json: {
    ...context,
    intent: final_intent,
    original_intent: intent,
    confidence,
    check_history_needed // Esta bandera le dirá a n8n si debe ir a buscar a Slack o no
  }
}];

// 1. Unir todo el texto del historial de Slack en un solo bloque
const messages = $input.all().map(item => item.json.text || '').join(' ');

// 2. Traer el contexto y la intención original que habíamos guardado
const context = $('Validate & Enrich Context').first().json;

// 3. Buscar el UUID del deal en el historial
const dealMatch = messages.match(/app.example.com\/records\/([0-9a-fA-F-]{36})/i);
const deal_id = dealMatch ? dealMatch[1] : null;

// 4. Lógica de decisión final
let final_intent = context.original_intent; // Lo que la IA detectó (ej. 'status')

if (deal_id) {
  // ¡Bingo! Encontramos el link en el pasado. Lo inyectamos al contexto.
  context.deal_id = deal_id;
  context.application_id = deal_id;
  context.has_deal_link = true;
} else {
  // Definitivamente no hay link en todo el hilo. El usuario debe enviarlo.
  final_intent = 'missing_link';
}

// 5. Devolver el paquete limpio para el Switch
return [{
  json: {
    ...context,
    intent: final_intent
  }
}];

let intent, channel_id, thread_ts, data;
let message = "";

// 1. DETECTOR DE CARRILES
try {
    const context = $('Validate & Enrich Context').first().json;
    intent = context.intent;
    channel_id = context.channel_id;
    thread_ts = context.thread_ts || "";
    data = $input.first().json;
} catch (error) {
    intent = 'proactive_alert';
    data = $input.first().json; // Ahora toma los datos directamente del nodo Enrich
    channel_id = data.channel_id;
    thread_ts = data.thread_ts || "";
}

// 2. FORMATEO DE MENSAJES
switch(intent) {

  case 'proactive_alert': {
    const dealName = data.deal_name || 'Unknown Deal';

    // Si el nodo Enrich encontró el UUID usa el link real, sino, usa el de búsqueda.
    const dealLink = data.deal_url 
      ? `<${data.deal_url}|${dealName}>` 
      : `<https://app.example.com/records?search=${encodeURIComponent(dealName)}|${dealName} (search)>`;

    const faDisplay = (data.fa_name && data.fa_name !== 'Unknown') ? `👤 *FA:* ${data.fa_name}` : `👤 *FA:* Unassigned`;
    const lenderDisplay = (data.lender && data.lender !== 'Unknown') ? `🏦 *Lender:* ${data.lender}` : `🏦 *Lender:* Unknown`;

    message = `🔔 *New Update for your SBA*\n`;
    message += `📌 *Deal:* ${dealLink}\n`; 
    message += `${faDisplay} | ${lenderDisplay}\n`;
    message += `──────────────────────\n`;
    message += `${(data.urgency_level || '').includes('URGENT') ? '🚨' : ((data.urgency_level || '').includes('PENDING') ? '⏳' : 'ℹ️')} *Status:* ${data.urgency_level || '🟡 PENDING'}\n`;
    message += `📝 *TL;DR:* ${data.tldr || 'No details provided.'}\n`;
    message += `👉 *Action:* ${data.required_action || 'Review email manually.'}`;
    break;
  }

  // ---> CARRILES ORIGINALES DE SLACK (SIN CAMBIOS) <---
  case 'status':
    message = `📋 *Deal Status: ${data.business_name || 'Unknown'}*\n`;
    message += `👤 *Advisor:* ${data.fa_name || 'Unassigned'}\n`;
    message += `📈 *Stage:* ${data.stage || 'N/A'}\n`;
    if (data.missing_stips && data.missing_stips.length > 0) {
      message += `⚠️ *Missing Documents:* ${data.missing_stips.join(', ')}\n`;
    } else {
      message += `✅ *Documents:* All stips completed.\n`;
    }
    message += `💡 *Next Action:* ${data.next_action || 'Awaiting update'}`;
    break;

  case 'missing':
  case 'snapshot':
    const icon = intent === 'missing' ? '📧' : '📊';
    const resultIcon = (data.outcome === 'sent' || data.outcome === 'completed') ? '✅' : '⚠️';
    message = `${icon} *Action Result:*\n${resultIcon} ${data.summary || 'Completed'}\n🔗 <${data.deal_url}|View Deal in Platform>`;
    break;

  case 'score':
    message = `⭐ *Deal Quality Score*\n`;
    message += `*Score:* ${data.score || 0}/100\n`;
    message += `*Rating:* ${data.rating || 'N/A'}\n`;
    message += `*Justification:* ${data.justificacion || 'No justification provided.'}\n`;
    message += `🔗 <${data.deal_url}|View Deal in Platform>`;
    break;

  case 'help':
    message = `👋 *Hi! I'm Operations Copilot.*\nI can help you with any SBA deal. Just write to me naturally or use these commands:\n• _"What's the status of this deal [link]"_\n• _"Send the missing documents email"_\n• _"Calculate the score for this deal"_\n• _"Generate the snapshot PDF"_`;
    break;

  case 'missing_link':
    message = `🔍 I'd love to help with that! However, I checked our conversation history and couldn't find a deal link. Could you please share the Platform deal URL here?`;
    break;

  default: 
    message = `🤖 Hmm, I'm not entirely sure how to proceed with that. Try asking for "status", "score", "missing docs", or simply type "help".`;
}

// 3. SALIDA
return [{
  json: {
    slack_message: message,
    channel_id: channel_id,
    thread_ts: thread_ts
  }
}];

const rawText = $input.first().json.text;
let emailData = {};

try {
  emailData = JSON.parse(rawText);
} catch (e) {
  emailData = { deal_name: "New SBA Deal", tldr: "Error procesando", required_action: "Revisar manual" };
}

return [{
  json: {
    ...emailData, // Pasa el lender, fa_name, etc.
    deal_name: emailData.deal_name || "New SBA Deal",
    intent: 'proactive_alert',
    channel_id: '<YOUR_SLACK_CHANNEL_ID>', // El ID de tu canal #micanal
    thread_ts: null
  }
}];

const alert = $('Standardize Proactive Alert').first().json;
const searchWrap = $('Search Deal by Name').first().json;
const rows = Array.isArray(searchWrap?.data) ? searchWrap.data : [];

// 1. Limpiador inteligente de nombres (quita LLC, acentos, mayúsculas)
const normalize = (s) => 
  String(s || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/\b(LLC|INC|CORP|CO|LTD)\b\.?/gi, '')
    .toLowerCase()
    .replace(/[^a-z0-9 ]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();

const target = normalize(alert.deal_name);

// 2. Sistema de puntuación para encontrar el mejor match
function scoreRow(row) {
  const names = [
    row.business_legal_name,
    row.application_name,
    row.business_name,
    row.client?.name,
  ].filter(Boolean);

  let best = 0;
  for (const n of names) {
    const nn = normalize(n);
    if (!nn || !target) continue;
    if (nn === target) best = Math.max(best, 1);
    else if (nn.includes(target) || target.includes(nn)) best = Math.max(best, 0.9);
  }
  return best;
}

// 3. Ordenamos los resultados por puntuación
const ranked = rows
  .map((r) => ({ r, score: scoreRow(r) }))
  .sort((a, b) => b.score - a.score);

const best = ranked[0]?.r || null;
const fa = best?.funding_advisor || {};

const faFromLf = [fa.first_name, fa.last_name].filter(Boolean).join(' ') || fa.name || '';
const faName = faFromLf || (alert.fa_name && alert.fa_name !== 'Unknown' ? alert.fa_name : 'Unassigned');

const dealId = best?.id || null;

// 4. Salida empaquetada lista para Slack
return [{
  json: {
    ...alert,
    deal_id: dealId,
    deal_url: dealId ? `https://app.example.com/records/${dealId}` : null,
    fa_name: faName,
    deal_match_found: !!dealId,
    deal_match_score: ranked[0]?.score ?? 0,
    intent: 'proactive_alert'
  }
}];
